window.__QUIZ_DATA__=[{"id":"theory>Biology>1999>1>a>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Name four similarities found in plant and animal cells","images":[],"marking_scheme":"-Cytoplasm, Nucleus, nucleolus, DNA, RNA, chromosomes, Cell membrane, Mitochondria, Golgi bodies, Endoplasmic reticulum, Nuclear membrane, Ribosomes.","marks":"7","difficulty":"1"},{"id":"theory>Biology>1999>1>a>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"In a tabular form list four different cells found in man and give a function for each of the cells.","images":[],"marking_scheme":"Types of human cells,Functions  Red blood cells/ corpuscles/ erythrocytes,perform circulatory/ excretory/ respiratory or transport functions; carry O2  to or round the body and remove CO2 from cells.  White blood cells/ leucocytes,Defend/ protect the body and provide immunity  Epidermal cells,protect the body against disease germs/infection or dehydration  Sperm cells/ spermatozoa,for reproduction/ fertilization  Nerve cells/ neurons,Transmit impulses or messages from nerve fibres  Ova/ eggs,for reproduction  muscle cells,form muscles for movement or locomotion and attachment of bones and give shape to the body  Bone cells / oesteoblast / oesteocytes,Form bones, give support to or aid movement and give shape to the body  Chondroblast/ cartilage,Attachment of bones (support)  Rods,Photo receptor in dim light  Cone,Photo receptor in bright light","marks":"7","difficulty":"2"},{"id":"theory>Biology>1999>1>b>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL THEORY","question":"Name the two types of cell divisions.","images":[],"marking_scheme":"-Mitosis   -Meiosis","marks":"2","difficulty":"1"},{"id":"theory>Biology>1999>1>b>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL THEORY","question":"Give two examples each of life processes involved in each type of the cell division.","images":[],"marking_scheme":"-Examples of life processes involved in mitosis are: Formation of new cells in the maiphigian layer of skin, Production of red blood cells and white blood cells in the bone marrow, Cell division in liver, Growth Spermatogenesis, Repair or healing of wound, Binary fission.    - Examples of life processes involved in meiosis are: Formation of sperms (male gametes), Formation of oval eggs (female gametes), Formation of pollen grains in anther of flowering plants, Formation of ovules (in ovary) of flowering plants.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>1>c","subject":"Biology","year":"1999","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Name the two types of reproduction usually associated with organisms.","images":[],"marking_scheme":"-Sexual   -Asexual","marks":"2","difficulty":"1"},{"id":"theory>Biology>1999>2>a>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Define the term metamorphosis.","images":[],"marking_scheme":"Metamorphosis refers to series of changes of forms or shapes from the fertilized egg (immature stage) to adult (mature stage or adulthood).","marks":"2","difficulty":"1"},{"id":"theory>Biology>1999>2>a>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Name the two types of metamorphosis that organisms undergo and mention two organisms that undergo each type.","images":[],"marking_scheme":"-Complete metamorphosis, e.g, Butterfly, Housefly, Bees, Wasp, Beetles, Mosquito   -Incomplete metamorphosis, e.g, Grasshoppers, Cockroach, Dragonfly , Locust, Aphids, Termites, Praying mantis","marks":"8","difficulty":"2"},{"id":"theory>Biology>1999>2>b>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"State four economic importance of insects and name an example of each of the insects involved.","images":[],"marking_scheme":"-Act as carriers, vectors or transmitters of diseases ( e.g anopheles mosquito, tsetsefly etc  -Act as pests and are destructive to life plants or stored food (e.g locust; grasshoppers weevil, crickets)  -As food or source of protein (e.g termites, honey, larval forms of some beetles, cricket, grasshopper)  -Life processes involved in meiosis used in biological control (e.g lady bird - used in control of aphids on plantations, praying mantis:- control of some insects)  -Serve as pollinating agents of flowering plants (e.g bees, butterflies, ants, moths, wasps, beetles).  -Soil insects for aeration or loosening of soil (e.g termites, crickets, dung - beetles).  -Insects as industrial material, (bee wax for candles, silk worms).  -Termitarium used in building lawn tennis courts  -Revenue yielding - e.g termites, larva of beetles e.t.c.  -Destroy furniture, books, clothes, wood e.t.c, e.g cockroaches and termites.","marks":"4","difficulty":"3"},{"id":"theory>Biology>1999>2>b>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"List four peculiar features of social insects.","images":[],"marking_scheme":"-They live together or form colonies  -They live in nests.  -Show or display division of labour.  -Show distinct castes.  -Members communicate with one another within the colonies.","marks":"6","difficulty":"2"},{"id":"theory>Biology>1999>3>a>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"What is Pollution?","images":[],"marking_scheme":"Pollution is the release of toxic or harmful substances into the environment by their natural forces or man and other animals to an extent that causes biological damage to man and his resources.","marks":"3","difficulty":"1"},{"id":"theory>Biology>1999>3>a>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"Name two pollutants each of air and water.","images":[],"marking_scheme":"-Pollutants of air are:Smoke, fumes, dust, harmful gases e.g sulphurdioxide, hydrogen sulphide, ammonia, chlorine/nitrogen oxides, carbon monoxide, pollen grains and soot.    -Pollutants of water are: sewage, excreta/faeces, pesticides, chemical wastes/chemicals from factories, fertilizers, slurry/waste from farms, petroleum/ crude oil, heated water, oil spillage.","marks":"4","difficulty":"1"},{"id":"theory>Biology>1999>3>b>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"State four effects of water pollution.","images":[],"marking_scheme":"-Destruction or death of valuable aquatic species such as sea birds, fishes e.t.c.  -Food chain is affected, or disrupted.  -Pollutants encourage bacterial growth leading to reduced amounts of dissolved oxygen/biological oxygen demand in water. This leads to death of fishes and other organisms.  -Causes algae blood or putrification while water is rendered unsafe for domestic, drinking, industrial use or recreation.  -It also leads to migration of water animals.","marks":"4","difficulty":"2"},{"id":"theory>Biology>1999>3>b>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Mention four ways of preventing water pollution in an environment.","images":[],"marking_scheme":"-There should be efficient and proper sewage disposal system.  -Dumping of refuse or petro-chemical by-products into rivers/streams/ponds or seas should be avoided.  -The use of efficient techniques to deal with or prevent oil spillage should be adopted.  -Industries should be sited away from residential areas and water bodies.  -Government /local authorities should strictly monitor all industrial wastes and carry out public enlightenment.  -Industrial effluents and hot water should be re-cycled.","marks":"4","difficulty":"2"},{"id":"theory>Biology>1999>3>c>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"Name three sources of noise pollution.","images":[],"marking_scheme":"-Factory or industrial noise.  -Aeroplane/aviation noise (taking off and landing of aeroplanes).  -Railway engine/locomotive noise.  -Automobile/ car horns/sirens.  -High pitched musical sounds from loud speakers/drumming.  -Noise from mills/sawmills/ grinding mills/electronic gadgets and generators.  -Artillary shots /shelling/canon shots.  -Thunder noise.","marks":"3","difficulty":"1"},{"id":"theory>Biology>1999>3>c>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"State three effects of noise pollution on man.","images":[],"marking_scheme":"-Loss of hearing /deafening /hard hearing/hearing difficulty.  -Emotional disorder/anxiety / fright and lack of concentration.  -High blood pressure/hypertension.  -General irritation/short temper.  -Changes in behaviour.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>4>a>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"Define the law of independent assortment.","images":[],"marking_scheme":"The law of independent assortment states that each member of alleles or contracting character may combine randomly with either member of another pair.","marks":"4","difficulty":"2"},{"id":"theory>Biology>1999>4>a>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"State the findings from Mendel's experiment involving white-flowered and red-flowered pea plants.","images":[],"marking_scheme":"On crossing white and red flowered pea plants, he obtained all red - flowered offspring, but on self-.crossing each of these red- flowered plants he obtained mixtures of red flowered and white flowered plants in the ratio of 3:1 (\u00be red / \u00bc white flowered).","marks":"4","difficulty":"3"},{"id":"theory>Biology>1999>4>a>iii","subject":"Biology","year":"1999","type":"Theory","sub_label":"iii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"Illustrate these findings by means of simple diagrams.","images":["data:image/png;base64,"],"marking_scheme":"Key for parental genotype e.g R for red, r for white","marks":"4","difficulty":"3"},{"id":"theory>Biology>1999>4>b","subject":"Biology","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"Explain why blood groups A and B in man can exist both in heterozygous and homozygous conditions while blood group 0 can only exist in homozygous state.","images":[],"marking_scheme":"Blood grouping in man is determined by three alternative genes (alleles) A, B, and 0. A person can only possess two (alleles) of the genes on a pair of homologous chromosomes. 0 is recessive to both A and B, hence it is possible to have blood group A and AA (homozygous) and AO (heterozygous) and group B as BB or BO. However, group 0 can only exist genotypically as 00 in the homozygous recessive state.","marks":"8","difficulty":"3"},{"id":"theory>Biology>1999>5>a>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"State the principles involved in the following methods of food preservation:  Salting.","images":[],"marking_scheme":"Salting:- It raises the osmotic concentration of food. and removes water from or dehydrates the food (ex - osmosis) to an intolerable level.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>5>a>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"State the principles involved in the following methods of food preservation:  Refrigeration","images":[],"marking_scheme":"Refrigeration: It provides lower temperature within the food, retards (slows down) biological processes in spoilage organisms in food and kills some micro-organisms or slows down the activities of spoilage organisms in food.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>5>a>iii","subject":"Biology","year":"1999","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"State the principles involved in the following methods of food preservation:  Drying","images":[],"marking_scheme":"Drying: It removes water or moisture and dehydrates food, prevents normal microbial activities which requires water and increases osmotic concentration of food which kills spoilage organism.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>5>a>iv","subject":"Biology","year":"1999","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"State the principles involved in the following methods of food preservation:  Smoking .","images":[],"marking_scheme":"Smoking: It creates or generates high temperature/heat Its carbon kills micro-organisms in food, causes dehydration, increases osmotic pressure and hence, killing of the microbes.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>5>a>v","subject":"Biology","year":"1999","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"State the principles involved in the following methods of food preservation:  Chemicals.","images":[],"marking_scheme":"Chemicals: It chokes /suffocates/ spoilage organisms in food, dehydrates/toxicates spoilage organism in food and finally kills organisms.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1999>5>b","subject":"Biology","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"State four problems that may be caused by human overpopulation","images":[],"marking_scheme":"-Reduction of availability of land for agriculture.  -Shortage of food resulting in competition and starvation.  -Causes unemployment.  -Reduces per capita income/causes poverty.  -Causes outbreak of disease / epidemics/ health hazard.  -Causes inadequate medical care, social welfare services and shelter.  -Leads to increased social vices like crimes, juvenile delinquency, drug abuse e.t.c and aggression.  -Causes inadequate educational facilities and other public utility services.","marks":"4","difficulty":"3"},{"id":"theory>Biology>1999>5>c","subject":"Biology","year":"1999","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"Explain three ways by which the Government may increase food production.","images":[],"marking_scheme":"-Distribution of high quality seeds and other planting stock which are high - yielding, disease/pest/drought resistant.  -Distribution of fertilizers and other agro - chemicals at subsidized rate to increase crop yield.  -Distribution of tractors/other farm machines/implements for hiring for easy and quicker cultivation of large farm/area of land.  -Providing extension services to local farmers to intimate them with modern farming practices/techniques.  -Establishment of river basin authorities which makes water available for irrigation and dry season farming.  -Good roads and stable markets, for easy distribution of products.  -Government should make available storage facility to prevent spoilage.  -Establishment of research institutes to research on food varieties.  -Government should grant agricultural loan to encourage farmers to produce more food.","marks":"6","difficulty":"2"},{"id":"theory>Biology>1999>6>a>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Define the term hydrosphere.","images":[],"marking_scheme":"Hydrosphere is the aquatic portion of the biosphere or life supporting living world or earth.","marks":"2","difficulty":"1"},{"id":"theory>Biology>1999>6>a>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Give three examples of hydrosphere.","images":[],"marking_scheme":"-Lake, Pools, Spring, Oceans, Ponds, Oasis, Rivers, Streams, Manny.","marks":"3","difficulty":"1"},{"id":"theory>Biology>1999>6>b>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"State the two laws of thermodynamics levels.","images":[],"marking_scheme":"-The first law of thermodynamics states that energy can neither be created nor destroyed.     -The second law of thermodynamics states that in any conversion of energy from one state to another, there is always a decrease in the amount of useful energy.","marks":"4","difficulty":"2"},{"id":"theory>Biology>1999>6>b>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Using the second law of thermodynamics, explain the energy flow across trophic levels","images":[],"marking_scheme":"Using the second law of thermodynamics, the energy flow across trophic levels can be explained as follows:    -The transfer of energy between trophic levels is not 100%. That means it is not completely transferred.  -Successive levels have less of useful energy and support fewer organisms.  -Primary producers/plants have the highest amount of energy and when herbivores feed on plants, the energy level is reduced.  -When carnivores consume the herbivores the energy level is further reduced.","marks":"3","difficulty":"3"},{"id":"theory>Biology>1999>6>c>i","subject":"Biology","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Name two local biotic communities in Nigeria and associate each type with a particular State in Nigeria.","images":[],"marking_scheme":"Local biotic communityStateTropical rainforestEdo/Delta/Ondo/Imo/Abia/Lagos/Anambra/Rivers/Bayelsa/Akwa-IbomSouthern Guinea SavannaEnugu/Kogi/Benue/Kwara/Oyo/Ebonyi/Osun/Ekiti.Northern Guinea SavannaPlateau/Kaduna/Bauchi/Niger/Taraba/Adarnawa/Kano.  Sahel SavannaBorno/Kastina/Sokoto/Yobe/Kebbi/Zamfara/Kano/Jigawa.Mangrove/Swamp/EstuarineRiver/Rivers/Akwalbom/Bayelsa/Ogun/Lagos/Ondo","marks":"4","difficulty":"1"},{"id":"theory>Biology>1999>6>c>ii","subject":"Biology","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"List three factors that affect organisms in the marine habitat.","images":[],"marking_scheme":"-Temperature, Salinity, Pressure, Turbidity/light penetration, Dissolved oxygen, Density of sea water, PH/hydrogen ion concentration, Waves /up-welling of water, Current and Tides.","marks":"1","difficulty":"2"},{"id":"theory>Biology>1999>6>c>iii","subject":"Biology","year":"1999","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State three adaptive features of sea weeds.","images":[],"marking_scheme":"-Possession of chloroplast/photosynthesis  -Absence of lignified tissue which makes them flexible and able to withstand wave actions  -Possession of hold fast for firm attachment to substratum or rocky surface  -Body covered with mucilage to reduce desiccation during low tide or on exposure  -Possession of air bladders for buoyancy.","marks":"3","difficulty":"3"}];